9242                    [this](Value *V) { return EphValues.contains(V); }) &&
9243            (allConstant(TE->Scalars) || isSplat(TE->Scalars) ||
9244             TE->Scalars.size() < Limit ||
9245             ((TE->getOpcode() == Instruction::ExtractElement ||
9246               all_of(TE->Scalars, IsaPred<ExtractElementInst, UndefValue>)) &&
