12711         V0 = Builder.CreateCmp(CI0->getPredicate(), LHS, RHS);
12712         auto *AltCI = cast<CmpInst>(E->getAltOp());
12713         CmpInst::Predicate AltPred = AltCI->getPredicate();
12714         V1 = Builder.CreateCmp(AltPred, LHS, RHS);
12715       } else {
12716         if (LHS->getType()->isIntOrIntVectorTy() && ScalarTy->isIntegerTy()) {
12717           unsigned SrcBWSz = DL->getTypeSizeInBits(
12718               cast<VectorType>(LHS->getType())->getElementType());
12719           unsigned BWSz = DL->getTypeSizeInBits(ScalarTy);
12720           if (BWSz <= SrcBWSz) {
12721             if (BWSz < SrcBWSz)
12722               LHS = Builder.CreateIntCast(LHS, VecTy, It->second.first);
12723             assert(LHS->getType() == VecTy && "Expected same type as operand.");
12724             if (auto *I = dyn_cast<Instruction>(LHS))
12725               LHS = propagateMetadata(I, E->Scalars);
12726             E->VectorizedValue = LHS;
12727             ++NumVectorInstructions;
12728             return LHS;
12729           }
12730         }
12731         V0 = Builder.CreateCast(
12732             static_cast<Instruction::CastOps>(E->getOpcode()), LHS, VecTy);
12733         V1 = Builder.CreateCast(
12734             static_cast<Instruction::CastOps>(E->getAltOpcode()), LHS, VecTy);
12735       }
12736       // Add V0 and V1 to later analysis to try to find and remove matching
12737       // instruction, if any.
12738       for (Value *V : {V0, V1}) {
12739         if (auto *I = dyn_cast<Instruction>(V)) {
12740           GatherShuffleExtractSeq.insert(I);
12741           CSEBlocks.insert(I->getParent());
12742         }
12743       }
12744 
12745       // Create shuffle to take alternate operations from the vector.
12746       // Also, gather up main and alt scalar ops to propagate IR flags to
12747       // each vector operation.
12748       ValueList OpScalars, AltScalars;
12749       SmallVector<int> Mask;
12750       E->buildAltOpShuffleMask(
12751           [E, this](Instruction *I) {
12752             assert(E->isOpcodeOrAlt(I) && "Unexpected main/alternate opcode");
12753             return isAlternateInstruction(I, E->getMainOp(), E->getAltOp(),
12754                                           *TLI);
12755           },
12756           Mask, &OpScalars, &AltScalars);
12757 
12758       propagateIRFlags(V0, OpScalars, E->getMainOp(), It == MinBWs.end());
12759       propagateIRFlags(V1, AltScalars, E->getAltOp(), It == MinBWs.end());
12760 
12761       Value *V = Builder.CreateShuffleVector(V0, V1, Mask);
12762       if (auto *I = dyn_cast<Instruction>(V)) {
12763         V = propagateMetadata(I, E->Scalars);
12764         GatherShuffleExtractSeq.insert(I);
12765         CSEBlocks.insert(I->getParent());
12766       }
12767 
12768       E->VectorizedValue = V;
12769       ++NumVectorInstructions;
12770 
12771       return V;
12772     }
12773     default:
12774       llvm_unreachable("unknown inst");
12775   }
12776   return nullptr;
12777 }
